if (! $this->hasAuthorizationTooltip() && ! $this->hasAuthorizationNotification()) {
    return $this->isAuthorized();
}

if ($this->table instanceof Model) {
    $array['context']['recordKey'] = $this->table->getKey();
} elseif (is_array($this->table)) {
    $array['context']['recordKey'] = $this->table[ArrayRecord::getKeyName()] ?? null;
} else {
    $array['context']['recordKey'] = $this->table;
}

if ($checkActionUsing) {
    Assert::assertTrue(
        $checkActionUsing($action),
        $generateMessageUsing ?
            $generateMessageUsing($prettyName, $livewireClass) :
            "Failed asserting that an action with the name [{$prettyName}] and provided configuration exists on the [{$livewireClass}] component.",
    );
}

if (! $this->option('force') && $this->checkForCollision($this->previewViewPath)) {
    throw new FailureCommandOutput;
}

try {
    $url = $storage->temporaryUrl(
        $file,
        now()->addMinutes(config('filament.temporary_file_url_expiry_minutes', 30))->endOfHour(),
    );
} catch (Throwable $exception) {
    // This driver does not support creating temporary URLs.
}

try {
    return $storage->temporaryUrl(
        $file,
        now()->addMinutes(config('filament.temporary_file_url_expiry_minutes', 30))->endOfHour(),
    );
} catch (Throwable $exception) {
    // This driver does not support creating temporary URLs.
}

foreach ($this->customBlocks as $key => $block) {
    if (is_string($key) && ($key::getId() === $id)) {
        return $key::toHtml($config, data: value($block) ?? []);
    } elseif (is_string($block) && ($block::getId() === $id)) {
        return $block::toHtml($config, data: []);
    }
}

try {
    return $storage->temporaryUrl(
        $state,
        now()->addMinutes(config('filament.temporary_file_url_expiry_minutes', 30))->endOfHour(),
    );
} catch (Throwable $exception) {
    // This driver does not support creating temporary URLs.
}

enum DatabaseNotificationsPosition: string
{
    case Topbar = 'topbar';

    case Sidebar = 'sidebar';
}

enum ThemeMode: string
{
    case System = 'system';

    case Light = 'light';

    case Dark = 'dark';
}

if ((! $this->isCachingSchemas) && $this->hasCachedSchema('filtersForm')) {
    return $this->getSchema('filtersForm');
}

enum SubNavigationPosition: string
{
    case Start = 'start';

    case End = 'end';

    case Top = 'top';
}

if (
    filled($defaultRedirect = Filament::getResourceEditPageRedirect()) &&
    $resource::hasPage($defaultRedirect) &&
    (($defaultRedirect !== 'view') || $resource::canView($this->getRecord()))
) {
    return $this->getResourceUrl($defaultRedirect, $this->getRedirectUrlParameters());
}

if ($action instanceof CreateAction) {
    Event::dispatch(RecordCreated::class, ['record' => $action->getRecord(), 'data' => $action->getData(), 'page' => $this]);
    Event::dispatch(RecordSaved::class, ['record' => $action->getRecord(), 'data' => $action->getData(), 'page' => $this]);
}

if ($action instanceof EditAction) {
    Event::dispatch(RecordUpdated::class, ['record' => $action->getRecord(), 'data' => $action->getData(), 'page' => $this]);
    Event::dispatch(RecordSaved::class, ['record' => $action->getRecord(), 'data' => $action->getData(), 'page' => $this]);
}

foreach (static::getGloballySearchableAttributes() as $attributes) {
    static::applyGlobalSearchAttributeConstraint(
        query: $query,
        search: $search,
        searchAttributes: Arr::wrap($attributes),
        isFirst: $isFirst,
    );
}

if (is_array($value)) {
    return $query->{$this->isInverse() ? 'whereNotIn' : 'whereIn'}($qualifiedColumn, $value);
}

if ($this instanceof Schema && $this->getParentComponent()) {
    return $this->getParentComponent()->getAllColumns();
}

if (! class_exists(VerifyBillableIsSubscribed::class)) {
    throw new LogicException('Laravel Spark is not installed.');
}

try {
    return $media->getTemporaryUrl(
        now()->addMinutes(config('filament.temporary_file_url_expiry_minutes', 30))->endOfHour(),
        $conversion ?? '',
    );
} catch (Throwable $exception) {
    // This driver does not support creating temporary URLs.
}

if (is_string($color)) {
    $color = Color::generatePalette($color);
} else {
    $color = array_map(
        fn (string | int $color): string | int => is_string($color) ? Color::convertToOklch($color) : $color,
        $color,
    );
}

if ($this->componentClasses[$componentKey][$color] ?? []) {
    return $this->componentClasses[$componentKey][$color];
}

if (preg_match("/^'(.*)'$/", $default, $matches) === 1) {
    return str_replace("''", "'", $matches[1]);
}

if (preg_match('/^\'(.*)\'$/', $default, $matches) === 1) {
    return str_replace("''", "'", $matches[1]);
}

if (preg_match('/^\'(.*)\'$/s', $default, $matches) === 1) {
    return str_replace("''", "'", $matches[1]);
}

foreach ($data as $key => $value) {
    if (
        isset($packedReferenceQueryBuilder['bindings'][$binding][$key])
        && $packedReferenceQueryBuilder['bindings'][$binding][$key] === $value
    ) {
        unset($packedQueryBuilder['bindings'][$binding][$key]);
    }
}

enum FontFamily: string
{
    case Sans = 'sans';

    case Serif = 'serif';

    case Mono = 'mono';
}

enum Operation: string
{
    case Create = 'create';

    case Edit = 'edit';

    case View = 'view';
}

enum VerticalAlignment: string
{
    case Start = 'start';

    case Center = 'center';

    case End = 'end';
}

if (
    (! $this->getTable()->isPaginated()) ||
    ($this->isTableReordering() && (! $this->getTable()->isPaginatedWhileReordering()))
) {
    return $setRecordLocales($this->cachedTableRecords = $this->hydratePivotRelationForTableRecords($query->get()));
}
